function isAgShurMainActor(actor) {
  if (!actor) return false;
  if (actor.getFlag?.("world", "agShurMain")) return true;
  return /Аг-Шур.*Бог Глаз|Ag-Shur.*God/i.test(actor.name ?? "");
}

function isRayControllerItem(item) {
  if (!item) return false;
  const name = item.name ?? "";
  return name === "Лучи из глаз" || /Малый Луч/i.test(name) || item.id === "AgShurEyeRays000" || item.id === "AgShurLegRay0000";
}

function itemMacroData(item) {
  return {
    name: String(item.name ?? "Луч Аг-Шура") + " ItemMacro",
    type: "script",
    img: item.img ?? "icons/magic/perception/eye-ringed-glow-angry-large-red.webp",
    scope: "global",
    command: PATCHED_RAY_MACRO,
    ownership: { default: CONST?.DOCUMENT_OWNERSHIP_LEVELS?.OWNER ?? 3 },
    flags: {
      dnd5e: { itemMacro: true },
      world: { agShurAntimagicRayTargetFilter: true, agShurPortableItemMacro: true }
    }
  };
}

function collectAgShurActors() {
  const actors = new Map();
  for (const actor of game.actors.contents) {
    if (isAgShurMainActor(actor)) actors.set(actor.uuid, actor);
  }
  for (const scene of game.scenes.contents) {
    for (const tokenDoc of scene.tokens.contents) {
      const synthetic = tokenDoc.actor;
      if (synthetic && isAgShurMainActor(synthetic)) actors.set(synthetic.uuid, synthetic);
    }
  }
  return Array.from(actors.values());
}

async function patchActor(actor, { dryRun = false, log = console.log } = {}) {
  const rayItems = actor.items.filter(isRayControllerItem);
  const details = { actor: actor.name, uuid: actor.uuid, rayItems: rayItems.map(item => item.name) };
  if (!rayItems.length) return { ...details, patched: 0, warning: "Не найдены предметы 'Лучи из глаз' или 'Малый Луч'." };
  if (dryRun) return { ...details, patched: rayItems.length };

  const updates = rayItems.map(item => ({
    _id: item.id,
    "flags.dae.macro": itemMacroData(item),
    "flags.itemacro.macro": itemMacroData(item),
    "flags.midi-qol.onUseMacroName": "[postActiveEffects]ItemMacro",
    "flags.world.agShurAntimagicRayTargetFilter": true
  }));
  await actor.updateEmbeddedDocuments("Item", updates);
  await actor.setFlag("ai-patcher", BUNDLE_ID, { patchedAt: new Date().toISOString(), items: rayItems.map(item => item.name) });
  log(actor.name + ": обновлены лучевые макросы (" + rayItems.map(item => item.name).join(", ") + ")");
  return { ...details, patched: rayItems.length };
}

export default async function patch(context = {}) {
  const { dryRun = false, log = console.log } = context;
  if (game.system.id !== "dnd5e") throw new Error("Патч рассчитан на D&D 5e / dnd5e.");
  const actors = collectAgShurActors();
  if (!actors.length) throw new Error("Не найден Аг-Шур. У импортированного актёра должен быть флаг world.agShurMain или имя с 'Аг-Шур' и 'Бог Глаз'.");
  const changed = [];
  for (const actor of actors) changed.push(await patchActor(actor, { dryRun, log }));
  return {
    ok: true,
    dryRun,
    changed,
    note: "Лучи из глаз и Малый Луч теперь исключают цели с эффектом Антимагического конуса Аг-Шура и цели внутри шаблона конуса."
  };
}
